code = """import json
import re

# Get the file path from the previous result variable
file_path = locals()['var_function-call-6798706679463811046']

# Load the clinical data
with open(file_path, 'r') as f:
    clinical_data = json.load(f)

# Regex to extract barcode (TCGA-XX-XXXX)
barcode_pattern = re.compile(r"TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}")

alive_patients = []

for entry in clinical_data:
    desc = entry.get('Patient_description', '')
    hist_type = entry.get('histological_type', '')
    
    # Check if Alive
    # The examples show "vital status: Alive", "vital status = Alive", "vital status is Alive"
    # We should also be careful about "Dead"
    
    is_alive = False
    if 'Alive' in desc:
        is_alive = True
    
    # Double check it doesn't say "Dead" (some descriptions might be complex)
    # But usually it's one or the other.
    # Let's rely on "Alive" being present.
    
    if is_alive:
        # Extract barcode
        match = barcode_pattern.search(desc)
        if match:
            barcode = match.group(0)
            alive_patients.append({
                'ParticipantBarcode': barcode,
                'histological_type': hist_type
            })

print("__RESULT__:")
print(json.dumps(alive_patients))"""

